import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import Paper from '@mui/material/Paper';
import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';
import Box from '@mui/material/Box';
import TextField from '@mui/material/TextField'; 


import { Routes, Route, NavLink, Link, useParams, Outlet }
from "react-router-dom";
//import './App.css';
import React, { useState, useEffect } from 'react';
import Button from '@mui/material/Button';
import { Update } from '@mui/icons-material';



function Pets() {
  
    // isLoaded keeps track of whether the initial load of pet data from the
    // server has occurred.  pets is the array of pets data in the table, and 
    // searchResults is the array of pets data after a search request.
    const [isLoaded, setIsLoaded] = useState(false);
    const [pets, setPets] = useState([]);
    const [searchResults, setSearchResults] = useState([]);


    const [isUpdated, setIsUpdated] = useState(false);
    const [id, setID] = useState(0);


    const confirmEdit = (id) => {
      setID(id)
      setIsUpdated(true);
    }

    // Handle form submission
    const handleSubmit = (event) => {
      event.preventDefault();
      const data = new FormData(event.currentTarget);
      const animal = data.get('animal');
      const description = data.get('description');
      const age = data.get('age');
      const price = data.get('price');
    
      updatePet(id, animal, description, age, price);
      setIsUpdated(false);
    };



    // fetches all pet data from the server
    function fetchPets()
    {
      fetch("http://localhost:3001/api?act=getall")
      .then(res => res.json())
      .then(
        (result) => {
          setIsLoaded(true);
          setPets(result);
        })    
    }

    
    // use fetchPets as an effect with an empty array as a 2nd argument, which 
    // means fetchPets will ONLY be called when the component first mounts
    useEffect(fetchPets, []);
    
    // Inserts a pet with hardcoded data in the URL for each query parameter, we 
    // could insert a pet with custom data by building a string like this:
    //
    // let url = "http://localhost:3001/api?act=add&animal=" + animal + ...
    //
    // fetch(url)
    // .then( ... )...
    //
    function addPet(animal, description, age, price)
    {
      fetch("http://localhost:3001/api?act=add&animal=" + animal + "&description="+ description + "&age="+ age + "&price=" + price)
      .then(res => res.json())
      .then(
        (result) => {
          fetchPets();
        })    
    }
  
    // Deletes a pet from the pet inventory, using a hardcoded id query parameter
    // Again we could delete a pet with custom data by building a string like:
    //
    // let url = "http://localhost:3001/api?act=delete&id=" + id
    //
    // fetch(url)
    // .then( ... )...
    //
    // 
    function deletePet(id)
    {
      fetch("http://localhost:3001/api?act=delete&id=" + id)
      .then(res => res.json())
      .then(
        (result) => {
          fetchPets();
        })    
    }


    
  
    // Updates a pet in the pet inventory.  Again we use hardcoded data but 
    // could build a custom fetch URL string.
    function updatePet(id, animal, description, age, price)
    {

      fetch("http://localhost:3001/api?act=update&id=" + id + "&animal="+ animal + "&description="+ description + "&age=" + age + "&price=" + price)
      .then(res => res.json())
      .then(
        (result) => {
          fetchPets();
        });
    }  
    
    // Searches for pets in the pet inventory.  Again we use hardcoded data but
    // we could build a custom fetch URL string.
    function searchPet()
    {
      fetch("http://localhost:3001/api?act=search&term=friendly%20with")
      .then(res => res.json())
      .then(
        (result) => {
          setSearchResults(JSON.stringify(result));
        });
    }



    function returnForm(){
      if(isUpdated){
      return (
        <div>
          <h3>
            Edit a pet
          </h3>
          <form onSubmit={handleSubmit}>
            <div id="form-container">
            <div class="form-elements">
                <label>
                    Animal
                </label>
                <input type='text' name='animal' id='animal-edit' />
            </div>
            <div class="form-elements">
                <label>
                    Description
                </label>
                <input type='text' name='description' id='description-edit' />
            </div>
            <div class="form-elements">
                <label>
                    Age
                </label>
                <input type='text' name='age' id='age-edit' />
            </div>
            <div class="form-elements">
                <label>
                    Price
                </label>
                <input type='text' name='price' id='price-edit' />
            </div>
            <Button variant="contained" type="submit">Confirm Edit</Button>
            <Button variant="contained" onClick={() => setIsUpdated(false)}>Cancel</Button>
            </div>
          </form>
          </div>
      )
      }
    }

    if (!isLoaded) {
      return <div>Loading...</div>;
    } else {
      return (
        <Box sx={{m:4}}>
        <TableContainer component={Paper} id="table">
          <Table sx={{midWidth: 700}} aria-label ="simple table">
            <TableHead>
              <TableRow>
                <TableCell>Animal</TableCell>
                <TableCell>Description</TableCell>
                <TableCell>Age</TableCell>
                <TableCell>Price</TableCell>
                <TableCell>Delete</TableCell>
                <TableCell>Update</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
            {pets.map(pet => (
              <TableRow key={pet.id}>
                <TableCell>{pet.animal}</TableCell> 
                <TableCell>{pet.description}</TableCell>
                <TableCell>{pet.age}</TableCell>
                <TableCell>{pet.price}</TableCell>
                <TableCell>
                  <Button variant="contained" onClick={() => deletePet(pet.id)}><DeleteIcon /></Button>
                </TableCell>
                <TableCell>
                  <Button variant="contained" onClick={() => confirmEdit(pet.id)}> <EditIcon /> </Button>
                </TableCell>
                {isUpdated && id==pet.id? <TableCell><Button variant="contained" onClick={() => setIsUpdated(false)}>Cancel?</Button></TableCell> : ""}
              </TableRow>
            ))}
            </TableBody>
          </Table>
          </TableContainer>
          <br />
          {isUpdated ? returnForm() : ""}
          <br />
          <h3>
            Add a pet
          </h3>
          <form>
            <div id="form-container">
            <div class="form-elements">
                <label>
                    Animal
                </label>
                <input type='text' id='animal' />
            </div>
            <div class="form-elements">
                <label>
                    Description
                </label>
                <input type='text' id='description' />
            </div>
            <div class="form-elements">
                <label>
                    Age
                </label>
                <input type='text' id='age' />
            </div>
            <div class="form-elements">
                <label>
                    Price
                </label>
                <input type='text' id='price' />
            </div>
            <Button variant="contained" onClick={() => addPet(document.getElementById('animal').value, document.getElementById('description').value, document.getElementById('age').value, document.getElementById('price').value)}>Add Pet</Button>
            </div>
          </form>
          <br />
        </Box>
      );
    }
  }
function Inventory() {
    return (
        <div>
        <h1>Inventory</h1>
        <p>Welcome to the Pet Store</p>
        <Pets/>
        </div>
    );
}
export default Inventory;
